    const findings = {
        lab_runtime_unavailable: ['No hubo runtime lab estable disponible en esta pasada', 'PerfAtlas no pudo obtener una ruta de ejecución lab fiable para esta pasada.', 'Activa un runtime Lighthouse local o una clave Google PSI/CrUX y vuelve a lanzar la auditoría.'],
        document_redirect_hops: ['Las redirecciones aún retrasan la respuesta HTML final', 'Al menos un documento muestreado necesita un salto extra antes de que el navegador pueda parsear el HTML final.', 'Apunta enlaces internos, canonicals y URLs de marketing directamente a la URL pública final cuando sea posible, y limita las redirecciones inevitables a un solo salto.'],
        compression_missing: ['Falta compresión en recursos internos muestreados', 'Recursos internos muestreados siguen sirviéndose sin señal de compresión de texto.', 'Activa Brotli o gzip de forma coherente para HTML, CSS, JS y otros recursos de texto en producción.'],
        cache_policy_weak: ['El cache a largo plazo es débil en recursos internos muestreados', 'Varios recursos internos muestreados no anuncian una política de cache duradera.', 'Aplica headers de cache fuertes a assets versionados y reserva políticas cortas solo para contenido mutable.'],
        blocking_markup_structure: ['Scripts síncronos y hojas de estilo siguen pesando en el arranque', 'La estructura HTML bruta todavía sugiere presión evitable en el arranque antes de sondas lab profundas.', 'Reduce el fan-out del head, difiere scripts no críticos y deja solo el CSS del primer viewport en la ruta de arranque.'],
        field_data_unavailable: ['No hay datos field confirmados para este objetivo', 'PerfAtlas no confirmó un dataset CrUX utilizable para este objetivo público.', 'Añade una clave CrUX/Google o relanza cuando el objetivo tenga suficiente tráfico público medible.'],
        field_lcp_poor: ['Largest Contentful Paint es lento en datos field', 'Los datos reales de usuarios muestran un LCP p75 por encima del umbral recomendado.', 'Optimiza la ruta del elemento LCP, la respuesta servidor, los recursos bloqueantes y los medios hero.'],
        field_inp_poor: ['La interacción es lenta en datos field', 'Los datos reales de usuarios muestran un INP p75 por encima del umbral recomendado.', 'Reduce tareas largas, hidratación costosa, scripts terceros y JavaScript crítico.'],
        field_cls_poor: ['Los cambios de layout son demasiado altos', 'Los datos field indican inestabilidad visual perceptible por usuarios.', 'Reserva dimensiones, estabiliza componentes tardíos y evita inyectar contenido por encima del viewport.'],
        lab_lcp_slow: ['El LCP es lento en runs lab', 'El run lab representativo muestra un Largest Contentful Paint lento.', 'Optimiza el elemento LCP, reduce CSS/JS bloqueantes, comprime medios hero y acorta la respuesta servidor.'],
        lab_main_thread_heavy: ['El main-thread bloquea demasiado en runs lab', 'El run lab muestra demasiado trabajo bloqueante en el hilo principal.', 'Difiere scripts no críticos, reduce la hidratación, divide tareas largas y mueve trabajo costoso fuera de la ruta crítica.'],
        lab_payload_bloat: ['El payload total y el número de requests son altos', 'El run lab representativo carga demasiados bytes o demasiadas requests.', 'Reduce peso JS y media, consolida recursos y elimina terceros o duplicados de bajo valor.'],
        lab_server_response_slow: ['El tiempo de respuesta servidor ralentiza la ruta crítica', 'El backend o edge retrasa materialmente el inicio del render.', 'Reduce latencia origin, mejora cache y optimiza trabajo servidor en rutas críticas.'],
        render_blocking_resources: ['Recursos bloqueantes aún retrasan el arranque', 'El render crítico se retrasa por hojas de estilo o scripts bloqueantes.', 'Inlinea o separa CSS crítico, difiere scripts no esenciales y precarga solo recursos que desbloquean el primer paint.'],
        unused_javascript_lab: ['JavaScript sin usar sigue pesando en la ruta representativa', 'El run lab todavía muestra una cantidad significativa de JavaScript entregado pero no usado en esta ruta.', 'Divide bundles de forma más agresiva, difiere código no crítico y elimina scripts terceros de bajo valor.'],
        unused_css_lab: ['CSS sin usar sigue inflando la ruta crítica de render', 'El run representativo entrega CSS que esta ruta no necesita.', 'Limpia CSS sin usar, separa estilos por ruta cuando sea razonable y deja solo CSS del primer viewport en el arranque.'],
        offscreen_images_lab: ['Imágenes fuera de pantalla aún compiten con el render crítico', 'La ruta representativa sigue gastando ancho de banda en imágenes innecesarias en el primer viewport.', 'Lazy-load imágenes fuera de pantalla, sirve variantes responsive más ajustadas y reserva eager loading para medios del primer viewport.'],
        third_party_lab_summary: ['El código tercero sigue costando demasiado en la ruta representativa', 'El run lab atribuye una parte significativa del trabajo o bytes a recursos terceros.', 'Retrasa o elimina terceros de bajo valor y deja dependencias inevitables fuera de la ruta crítica.'],
        lab_cache_ttl_opportunity: ['La ruta representativa aún tiene una oportunidad de cache TTL', 'El run lab aún ve recursos que podrían anunciar una duración de cache más fuerte.', 'Refuerza la política de cache de recursos versionados y verifica headers públicos finales tras el despliegue.'],
        lab_text_compression_opportunity: ['La ruta representativa aún tiene una oportunidad de compresión de texto', 'El run lab aún ve recursos de texto comprimibles demasiado costosos en red.', 'Activa compresión de texto coherente en la ruta pública final y verifica headers de producción.'],
        document_ttfb_slow: ['El tiempo de respuesta del documento es lento en páginas muestreadas', 'Varias páginas muestreadas muestran un inicio de respuesta lento antes de que pueda comenzar el render.', 'Perfila latencia origin, cachea rutas calientes y vuelve las rutas críticas compatibles con edge cuando sea posible.'],
        html_document_heavy: ['El payload HTML es pesado en páginas muestreadas', 'La respuesta HTML inicial transporta mucho markup o payload inline antes incluso de subrecursos.', 'Reduce markup servidor, mueve datos inline grandes fuera del HTML cuando sea seguro y deja inline solo recursos críticos.'],
        document_compression_missing: ['Los documentos HTML no se comprimen de forma coherente', 'Algunos documentos HTML muestreados se transfieren sin señal clara de compresión de texto.', 'Activa compresión en respuestas HTML de producción y verifica la ruta pública final.'],
        static_assets_uncacheable: ['Algunos recursos estáticos son explícitamente no cacheables', 'Recursos estáticos internos devuelven directivas que impiden su reutilización eficiente.', 'Separa políticas HTML mutables y recursos versionados para que los archivos inmutables sean cacheables.'],
    };
    Object.entries(findings).forEach(([key, [title, diagnostic, fix]]) => {
        MESSAGES.es.perfatlas[`findingTitle_${key}`] = title;
        MESSAGES.es.perfatlas[`findingDiagnostic_${key}`] = diagnostic;
        MESSAGES.es.perfatlas[`findingFix_${key}`] = fix;
    });
